const server = http.createServer(app);

module.exports = app;

// src/modules/projects/service.js
const { randomUUID } = require('node:crypto');

const projectsStore = {};

async function getAllProjects() {
  return Object.values(projectsStore);
}

async function createProject(name) {
  const project = { id: randomUUID(), name };
  projectsStore[project.id] = project;
  return project;
}

async function getProjectById(projectId) {
  return projectsStore[projectId];
}

module.exports = { getAllProjects, createProject, getProjectById };

// src/modules/tasks/routes.js
const express = require('express');
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', async (req, res) => {
  const status = req.query.status;
  try {
    const tasks = await tasksService.getTasksByProjectId(req.params.projectId, status);
    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.post('/', async (req, res) => {
  const { description } = req.body;
  if (!description) {
    return sendError(res, 400, 'INVALID_INPUT', 'Description is required');
  }
  try {
    const task = await tasksService.createTask(req.params.projectId, description);
    res.status(201).json({ task });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.patch('/:taskId', async (req, res) => {
  const { status } = req.body;
  if (!status || ![ 'todo', 'done' ].includes(status)) {
    return sendError(res, 400, 'INVALID_INPUT', 'Invalid task status');
  }
  try {
    const updatedTask = await tasksService.updateTaskStatus(req.params.projectId, req.params.taskId, status);
    res.json({ task: updatedTask });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/tasks/service.js
const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');
const { sendError } = require('../../lib/errors');

const tasksStore = {};

async function getTasksByProjectId(projectId, status) {
  const project = await projectsService.getProjectById(projectId);
  if (!project) {
    return null;
  }
  let tasks = tasksStore[projectId] || [];
  if (status) {
    tasks = tasks.filter(task => task.status === status);
  }
  return tasks;
}

async function createTask(projectId, description) {
  const project = await projectsService.getProjectById(projectId);
  if (!project) {
    return null;
  }
  if (!tasksStore[projectId]) {
    tasksStore[projectId] = [];
  }
  const task = { id: randomUUID(), description, status: 'todo' };
  tasksStore[projectId].push(task);
  return task;
}

async function updateTaskStatus(projectId, taskId, status) {
  const project = await projectsService.getProjectById(projectId);
  if (!project) {
    return null;
  }
  let tasks = tasksStore[projectId] || [];
  const task = tasks.find(t => t.id === taskId);
  if (!task) {
    return null;
  }
  if (![ 'todo', 'done' ].includes(status)) {
    return null;
  }
  task.status = status;
  return task;
}

module.exports = { getTasksByProjectId, createTask, updateTaskStatus };

// src/modules/members/routes.js
const express = require('express');
const membersService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_INPUT', 'Both userId and role are required');
  }
  try {
    const member = await membersService.addMember(req.params.projectId, userId, role);
    res.status(201).json({ member });
  } catch (error) {
    if (error.code === 'DUPLICATE_MEMBER') {
      return sendError(res, 409, 'DUPLICATE_MEMBER', error.message);
    }
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/members/service.js
const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');
const { sendError } = require('../../lib/errors');

const membersStore = {};

async function addMember(projectId, userId, role) {
  const project = await projectsService.getProjectById(projectId);
  if (!project) {
    return null;
  }
  if (membersStore[projectId] && membersStore[projectId][userId]) {
    throw { code: 'DUPLICATE_MEMBER', message: 'Member already exists in this project' };
  }
  if (!membersStore[projectId]) {
    membersStore[projectId] = {};
  }
  const member = { id: randomUUID(), userId, role };
  membersStore[projectId][userId] = member;
  return member;
}

module.exports = { addMember };

